
"use client"

import { useState, useCallback, useEffect } from 'react';
import { generateAISignal, AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { useUser, useFirestore } from '@/firebase';
import { collection, addDoc, serverTimestamp, doc, updateDoc, onSnapshot, increment } from 'firebase/firestore';
import { toast } from '@/hooks/use-toast';

/**
 * useTradingSignals - Core hook for managing AI signals and VIP limits.
 * STRICT LOGIC: Default is Locked/Free. VIP only after DB verified payment.
 */
export const useTradingSignals = () => {
  const { user } = useUser();
  const db = useFirestore();
  
  const [loading, setLoading] = useState(false);
  const [signals, setSignals] = useState<Record<string, AISignalOutput | null>>({});
  const [profile, setProfile] = useState<any>(null);
  const [isSyncing, setIsSyncing] = useState(true);

  // Live Firestore profile listener - The ONLY source of truth for VIP status
  useEffect(() => {
    if (!user || !db) {
      setIsSyncing(false);
      return;
    }

    const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
    const unsubscribe = onSnapshot(profileRef, (snap) => {
      if (snap.exists()) {
        setProfile(snap.data());
      } else {
        // Fallback for missing profile
        setProfile({ isSubscribed: false, freeSignalsUsed: 0 });
      }
      setIsSyncing(false);
    }, (err) => {
      console.error("Critical Sync Error:", err);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [user, db]);

  // Derive VIP status: Strictly DB check + Admin exception
  // Initial state is ALWAYS false until profile data is loaded and verified
  const isVip = profile ? (profile.isSubscribed === true || user?.email === 'HassanDeeb@example.com') : false;
  const signalsUsed = profile?.freeSignalsUsed || 0;

  const fetchSignal = useCallback(async (symbol: string, type: 'Forex' | 'Crypto') => {
    if (loading || !user || !db || !profile) return;

    // HARD LOCK: 7 signal limit for non-VIPs
    if (!isVip && signalsUsed >= 7) {
      toast({ 
        title: "Limit Reached", 
        description: "Standard account limit: 7 signals. Upgrade to VIP to unlock more.",
        variant: "destructive"
      });
      return 'limit_reached';
    }

    setLoading(true);
    try {
      const result = await generateAISignal({ instrumentName: symbol, instrumentType: type });
      
      setSignals(prev => ({ ...prev, [symbol]: result }));
      
      const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
      
      // Counter increments only for Free members
      if (!isVip) {
        updateDoc(profileRef, {
          freeSignalsUsed: increment(1),
          updatedAt: serverTimestamp()
        });
      }

      // Record in Personal History (VIP tracking benefit)
      const historyRef = collection(db, 'users', user.uid, 'signalHistory');
      addDoc(historyRef, {
        symbol,
        type,
        ...result,
        viewedAt: serverTimestamp(),
        // Result simulation for prototype tracker
        pipsResult: Math.floor(Math.random() * 80) + 20 
      });
      
      return 'success';
    } catch (error) {
      console.error("Signal Execution Error:", error);
      toast({ title: "Terminal Error", description: "Analytical core failed to generate signal.", variant: "destructive" });
      return 'error';
    } finally {
      setLoading(false);
    }
  }, [user, db, loading, profile, isVip, signalsUsed]);

  return {
    loading,
    signals,
    fetchSignal,
    profile,
    isSyncing,
    isVip,
    signalsUsed
  };
};
